-- create "inbounds" table
CREATE TABLE "inbounds" ("id" uuid NOT NULL, "tenant_id" uuid NOT NULL, "created_at" timestamptz NOT NULL, "created_by" uuid NULL, "updated_at" timestamptz NULL, "updated_by" uuid NULL, "deleted_at" timestamptz NULL, "deleted_by" uuid NULL, "data_type_id" uuid NULL, "data_type_slug" character varying NULL, "data" jsonb NULL, "order_id" character varying NULL, "supplier_id" uuid NOT NULL, PRIMARY KEY ("id"));
-- create "inbound-items" table
CREATE TABLE "inbound-items" ("id" uuid NOT NULL, "tenant_id" uuid NOT NULL, "created_at" timestamptz NOT NULL, "created_by" uuid NULL, "updated_at" timestamptz NULL, "updated_by" uuid NULL, "deleted_at" timestamptz NULL, "deleted_by" uuid NULL, "data_type_id" uuid NULL, "data_type_slug" character varying NULL, "data" jsonb NULL, "sku" character varying NOT NULL, "quantity" bigint NOT NULL, "inbound_id" uuid NOT NULL, PRIMARY KEY ("id"), CONSTRAINT "inbound-items_inbounds_inboundItems" FOREIGN KEY ("inbound_id") REFERENCES "inbounds" ("id") ON UPDATE NO ACTION ON DELETE NO ACTION);
